"""Configuration loader and manager."""

import json
from pathlib import Path
from typing import Any, Dict

from loguru import logger

from src.exceptions.errors import ConfigurationError

_MISSING = object()  # sentinel for missing keys


class Config:
    """Configuration manager for Maimai Assistant."""

    def __init__(self, config_dir: str = None):
        if config_dir is None:
            # Resolve relative to project root (3 levels up from this file)
            config_dir = str(Path(__file__).parent.parent.parent / "config")
        self.config_dir = Path(config_dir)
        self._settings: Dict[str, Any] = {}
        self._selectors: Dict[str, Any] = {}
        self._message_templates: Dict[str, Any] = {}

        self._load_all()

    def _load_json(self, filename: str) -> Dict[str, Any]:
        """Load JSON configuration file."""
        filepath = self.config_dir / filename
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                return json.load(f)
        except FileNotFoundError:
            raise ConfigurationError(f"Configuration file not found: {filepath}")
        except json.JSONDecodeError as e:
            raise ConfigurationError(f"Invalid JSON in {filepath}: {e}")

    def _load_all(self):
        """Load all configuration files."""
        logger.info("Loading configuration files...")
        self._settings = self._load_json("settings.json")
        self._selectors = self._load_json("selectors.json")
        self._message_templates = self._load_json("message_templates.json")
        logger.info("Configuration loaded successfully")

    def get(self, key: str, default: Any = None) -> Any:
        """Get setting by dot-notation key (e.g., 'browser.headless').

        Returns the configured value, including explicit ``null`` (None).
        Only falls back to *default* when the key path does not exist.
        """
        keys = key.split('.')
        value = self._settings

        for k in keys:
            if isinstance(value, dict):
                value = value.get(k, _MISSING)
                if value is _MISSING:
                    return default
            else:
                return default

        return value

    def get_selector(self, selector_path: str) -> str:
        """Get selector by dot-notation path (e.g., 'search.keyword_input')."""
        keys = selector_path.split('.')
        value = self._selectors.get('selectors', {})

        for k in keys:
            if isinstance(value, dict):
                value = value.get(k)
                if value is None:
                    raise ConfigurationError(f"Selector not found: {selector_path}")
            else:
                raise ConfigurationError(f"Invalid selector path: {selector_path}")

        return value

    def get_template(self, template_name: str) -> Dict[str, Any]:
        """Get message template by name."""
        template = self._message_templates.get(template_name)
        if template is None:
            raise ConfigurationError(f"Message template not found: {template_name}")
        return template

    def list_templates(self) -> list:
        """List all available message template names."""
        return list(self._message_templates.keys())


def _deep_merge(base: Dict[str, Any], override: Dict[str, Any]) -> Dict[str, Any]:
    """Deep merge override into a copy of base. Override wins on conflicts."""
    import copy
    result = copy.deepcopy(base)
    for key, value in override.items():
        if key in result and isinstance(result[key], dict) and isinstance(value, dict):
            result[key] = _deep_merge(result[key], value)
        else:
            result[key] = copy.deepcopy(value)
    return result


def apply_profile(
    profile_name: str,
    config: Config = None,
    project_root: Path = None,
) -> None:
    """Override config data paths and optionally merge profile-local settings.

    Args:
        profile_name: Profile directory name (e.g. 'alice', 'bob')
        config: Config instance to modify (defaults to global)
        project_root: Project root for resolving paths (defaults to auto-detect)
    """
    if config is None:
        config = get_config()
    if project_root is None:
        project_root = Path(__file__).parent.parent.parent

    profile_dir = project_root / "data" / "profiles" / profile_name
    profile_dir.mkdir(parents=True, exist_ok=True)

    # Merge profile-local settings.json if it exists
    profile_settings_path = profile_dir / "settings.json"
    if profile_settings_path.exists():
        import json
        with open(profile_settings_path, 'r', encoding='utf-8') as f:
            profile_settings = json.load(f)
        config._settings = _deep_merge(config._settings, profile_settings)

    # Override all data.* paths to point under profile dir
    rel_profile = f"data/profiles/{profile_name}"
    data_overrides = {
        "database_path": f"{rel_profile}/maimai.db",
        "session_path": f"{rel_profile}/.session/maimai_session.json",
        "log_dir": f"{rel_profile}/logs",
        "screenshot_dir": f"{rel_profile}/screenshots",
        "export_dir": f"{rel_profile}/exports",
        "checkpoint_dir": f"{rel_profile}/.checkpoints",
    }
    if "data" not in config._settings:
        config._settings["data"] = {}
    config._settings["data"].update(data_overrides)

    logger.info(f"Profile '{profile_name}' applied — data dir: {profile_dir}")


# Global configuration instance
_config_instance = None


def get_config() -> Config:
    """Get global configuration instance."""
    global _config_instance
    if _config_instance is None:
        _config_instance = Config()
    return _config_instance

"""Pipeline checkpoint manager for resume capability.

Saves pipeline progress to a JSON file so that interrupted pipelines
can be resumed from where they left off.
"""

import json
import os
import tempfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional, Set

from loguru import logger


def _get_checkpoint_dir() -> Path:
    """Resolve checkpoint directory from config or use default."""
    project_root = Path(__file__).parent.parent.parent
    try:
        from src.utils.config import get_config

        config = get_config()
        configured = config.get("data.checkpoint_dir", "data/.checkpoints")
        path = Path(configured)
        return path if path.is_absolute() else project_root / path
    except Exception:
        return project_root / "data" / ".checkpoints"


class CheckpointManager:
    """Manages pipeline checkpoint save/load for resume support."""

    def __init__(self, checkpoint_id: Optional[str] = None):
        checkpoint_dir = _get_checkpoint_dir()
        checkpoint_dir.mkdir(parents=True, exist_ok=True)

        if checkpoint_id:
            self.checkpoint_path = checkpoint_dir / f"{checkpoint_id}.json"
        else:
            # Generate ID from timestamp
            ts = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
            self.checkpoint_path = checkpoint_dir / f"pipeline_{ts}.json"

        self._data: Dict[str, Any] = {}

    def save(
        self,
        keywords: tuple,
        template: str,
        variables: dict,
        company: tuple,
        location: Optional[str],
        max_pages: int,
        batch_pages: int,
        skip_messaged: bool,
        interactive: bool,
        completed_pages: int,
        sent_ids: List[str],
        seen_ids: List[str],
        total_results: Optional[dict] = None,
        mode: str = "search_center",
        dry_run: bool = False,
        exchange_phone: bool = False,
        exchange_wechat: bool = False,
        min_years: Optional[int] = None,
        max_years: Optional[int] = None,
    ) -> None:
        """Save current pipeline state to checkpoint file."""
        self._data = {
            "created_at": self._data.get("created_at", datetime.now(timezone.utc).isoformat()),
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "params": {
                "keywords": list(keywords),
                "template": template,
                "variables": variables,
                "company": list(company) if company else [],
                "location": location,
                "max_pages": max_pages,
                "batch_pages": batch_pages,
                "skip_messaged": skip_messaged,
                "interactive": interactive,
                "mode": mode,
                "dry_run": dry_run,
                "exchange_phone": exchange_phone,
                "exchange_wechat": exchange_wechat,
                "min_years": min_years,
                "max_years": max_years,
            },
            "progress": {
                "completed_pages": completed_pages,
                "sent_ids": sent_ids,
                "seen_ids": seen_ids,
                "total_results": total_results or {},
            },
        }

        try:
            tmp_fd, tmp_path = tempfile.mkstemp(dir=self.checkpoint_path.parent, suffix=".tmp")
            try:
                with os.fdopen(tmp_fd, "w", encoding="utf-8") as f:
                    json.dump(self._data, f, ensure_ascii=False, indent=2)
                os.replace(tmp_path, self.checkpoint_path)
            except BaseException:
                try:
                    os.unlink(tmp_path)
                except OSError:
                    pass
                raise
            logger.debug(f"Checkpoint saved: {self.checkpoint_path}")
        except Exception as e:
            logger.error(f"Failed to save checkpoint: {e}")
            raise

    @classmethod
    def load_latest(cls) -> Optional["CheckpointManager"]:
        """Load the most recent checkpoint file.

        Returns:
